import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Line, Bar } from "react-chartjs-2";
import "./PriceAnalytics.css";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = "http://localhost:7000/api";

const PriceAnalytics = () => {
  const [range, setRange] = useState("monthly");
  const [loading, setLoading] = useState(true);
  const [productList, setProductList] = useState([]);
  const [categoryList, setCategoryList] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");
  const [productData, setProductData] = useState([]);
  const [categoryData, setCategoryData] = useState([]);

  // Fetch dropdown data
  useEffect(() => {
    const fetchLists = async () => {
      try {
        const [productsRes, catsRes] = await Promise.all([
          axios.get(`${API_BASE}/prices`),
          axios.get(`${API_BASE}/categories`),
        ]);
        setProductList(productsRes.data || []);
        setCategoryList(catsRes.data.categories || []);
      } catch (err) {
        console.error("Dropdown fetch error:", err);
      }
    };
    fetchLists();
  }, []);

  // Fetch trend data
  useEffect(() => {
    const fetchTrends = async () => {
      setLoading(true);
      try {
        const [prodRes, catRes] = await Promise.all([
          axios.get(
            `${API_BASE}/price-report/trends?type=product&range=${range}${
              selectedProduct ? `&filter=${selectedProduct}` : ""
            }`
          ),
          axios.get(
            `${API_BASE}/price-report/trends?type=category&range=${range}${
              selectedCategory ? `&filter=${selectedCategory}` : ""
            }`
          ),
        ]);
        setProductData(prodRes.data);
        setCategoryData(catRes.data);
      } catch (err) {
        console.error("Error fetching trends:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchTrends();
  }, [range, selectedProduct, selectedCategory]);

  // 📊 Line chart (product)
  const lineChartData = {
    labels:
      productData[0]?.prices?.map((p) => p.date) || [],
    datasets: productData.flatMap((prod, i) => [
      {
        label: `${prod._id} - Avg Price`,
        data: prod.prices.map((p) => p.avgPrice),
        borderColor: `hsl(${i * 60}, 70%, 50%)`,
        backgroundColor: `hsla(${i * 60}, 70%, 50%, 0.2)`,
        tension: 0.4,
        fill: true,
      },
      {
        label: `${prod._id} - Difference`,
        data: prod.prices.map((p) => p.difference),
        borderColor: `hsl(${i * 60 + 180}, 70%, 50%)`,
        backgroundColor: `hsla(${i * 60 + 180}, 70%, 50%, 0.2)`,
        tension: 0.4,
        borderDash: [6, 4],
      },
    ]),
  };

  // 📊 Bar chart (category)
  const barChartData = {
    labels: categoryData[0]?.prices?.map((p) => p.date) || [],
    datasets: categoryData.flatMap((cat, i) => [
      {
        label: `${cat._id} - Avg Price`,
        data: cat.prices.map((p) => p.avgPrice),
        backgroundColor: `hsla(${i * 60}, 70%, 60%, 0.7)`,
      },
      {
        label: `${cat._id} - Difference`,
        data: cat.prices.map((p) => p.difference),
        backgroundColor: `hsla(${i * 60 + 180}, 70%, 60%, 0.5)`,
      },
    ]),
  };

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📊 Price Analytics Dashboard</h2>

      <div className="filter-row">
        <div className="filter-group">
          <label>📅 Range:</label>
          <select value={range} onChange={(e) => setRange(e.target.value)}>
            <option value="weekly">Weekly (Last 30 days)</option>
            <option value="monthly">Monthly (Last 6 months)</option>
          </select>
        </div>
      </div>

      {loading ? (
        <p className="no-data">Loading analytics...</p>
      ) : (
        <div className="chart-grid">
          <div className="chart-card">
            <div className="chart-header">
              <h3>📈 Product-wise Price Trends</h3>
              <select
                className="dropdown-select"
                value={selectedProduct}
                onChange={(e) => setSelectedProduct(e.target.value)}
              >
                <option value="">All Products</option>
                {productList.map((p) => (
                  <option key={p._id} value={p.name}>
                    {p.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="chart-container">
              {lineChartData.labels.length > 0 ? (
                <Line
                  data={lineChartData}
                  options={{
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: { legend: { position: "bottom" } },
                    scales: { y: { beginAtZero: true } },
                  }}
                />
              ) : (
                <p className="no-data">No data available</p>
              )}
            </div>
          </div>

          <div className="chart-card">
            <div className="chart-header">
              <h3>📉 Category-wise Price Trends</h3>
              <select
                className="dropdown-select"
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
              >
                <option value="">All Categories</option>
                {categoryList.map((c) => (
                  <option key={c._id} value={c.name}>
                    {c.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="chart-container">
              {barChartData.labels.length > 0 ? (
                <Bar
                  data={barChartData}
                  options={{
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: { legend: { position: "bottom" } },
                    scales: { y: { beginAtZero: true } },
                  }}
                />
              ) : (
                <p className="no-data">No data available</p>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PriceAnalytics;
